import{_ as a,o as r,c as d,ak as e}from"./chunks/framework.DwHlt8HN.js";const s=JSON.parse('{"title":"JVM 性能调优","description":"","frontmatter":{},"headers":[],"relativePath":"high-performance/jvm/index.md","filePath":"high-performance/jvm/index.md","lastUpdated":1774360456000}'),h={name:"high-performance/jvm/index.md"};function i(l,t,o,n,m,p){return r(),d("div",null,[...t[0]||(t[0]=[e('<h1 id="jvm-性能调优" tabindex="-1">JVM 性能调优 <a class="header-anchor" href="#jvm-性能调优" aria-label="Permalink to “JVM 性能调优”">​</a></h1><p>凌晨 3 点，你被一阵急促的告警惊醒。</p><p>监控系统显示：服务器 CPU 100%，响应时间暴涨 10 倍。用户无法下单，订单量归零。</p><p>你登录服务器，执行 <code>jstack</code> 查看线程堆栈——满屏的 GC 线程在疯狂运行。GC 日志显示：每 30 秒触发一次 Full GC，每次 GC 后内存迅速耗尽。</p><p>你慌了：这是内存泄漏？还是 GC 参数配错了？</p><p>你查了半天，发现问题根源是一个 <code>static Map</code> 持有了一百万个用户会话，导致内存持续增长，最终触发 OOM。</p><p><strong>Java 应用的性能问题，有一半和 JVM 脱不了关系。</strong></p><p>本模块从 JVM 参数体系讲起，涵盖 GC 调优实战、内存优化与 OOM 排查，助你成为 JVM 调优专家。</p><hr><h2 id="模块速览" tabindex="-1">模块速览 <a class="header-anchor" href="#模块速览" aria-label="Permalink to “模块速览”">​</a></h2><h3 id="jvm-基础与参数" tabindex="-1">JVM 基础与参数 <a class="header-anchor" href="#jvm-基础与参数" aria-label="Permalink to “JVM 基础与参数”">​</a></h3><table tabindex="0"><thead><tr><th>文档</th><th>简介</th></tr></thead><tbody><tr><td><a href="/high-performance/jvm/param-type">JVM 参数类型与选择</a></td><td>标准参数、非标准参数、高级参数</td></tr><tr><td><a href="/high-performance/jvm/heap-param">堆内存参数配置</a></td><td>堆大小、分代比例</td></tr><tr><td><a href="/high-performance/jvm/metaspace-param">元空间参数配置</a></td><td>元空间大小与溢出排查</td></tr><tr><td><a href="/high-performance/jvm/gc-param">GC 参数配置</a></td><td>垃圾收集器选择与参数</td></tr><tr><td><a href="/high-performance/jvm/debug-param">调试与诊断参数</a></td><td>-XX 参数实战</td></tr></tbody></table><h3 id="gc-调优实战" tabindex="-1">GC 调优实战 <a class="header-anchor" href="#gc-调优实战" aria-label="Permalink to “GC 调优实战”">​</a></h3><table tabindex="0"><thead><tr><th>文档</th><th>简介</th></tr></thead><tbody><tr><td><a href="/high-performance/jvm/gc-log">GC 日志分析</a></td><td>GC 日志配置与解读</td></tr><tr><td><a href="/high-performance/jvm/gc-visualize">GC 日志可视化</a></td><td>GCeasy、GCViewer 工具使用</td></tr><tr><td><a href="/high-performance/jvm/minor-gc">Minor GC 分析</a></td><td>年轻代GC原理与优化</td></tr><tr><td><a href="/high-performance/jvm/full-gc">Full GC 分析与排查</a></td><td>Full GC 原因与解决</td></tr><tr><td><a href="/high-performance/jvm/g1-param">G1 收集器参数</a></td><td>G1调优核心参数</td></tr><tr><td><a href="/high-performance/jvm/g1-tuning">G1 调优实战</a></td><td>G1最佳实践</td></tr><tr><td><a href="/high-performance/jvm/cms-tuning">CMS 收集器调优</a></td><td>CMS调优与问题排查</td></tr><tr><td><a href="/high-performance/jvm/gc-recommend">GC 推荐配置</a></td><td>不同场景的推荐配置</td></tr></tbody></table><h3 id="内存问题与-oom-排查" tabindex="-1">内存问题与 OOM 排查 <a class="header-anchor" href="#内存问题与-oom-排查" aria-label="Permalink to “内存问题与 OOM 排查”">​</a></h3><table tabindex="0"><thead><tr><th>文档</th><th>简介</th></tr></thead><tbody><tr><td><a href="/high-performance/jvm/heap-oom">堆内存溢出（OOM）排查</a></td><td>MAT、Java VisualVM 使用</td></tr><tr><td><a href="/high-performance/jvm/direct-memory-oom">直接内存溢出排查</a></td><td>DirectByteBuffer 泄漏</td></tr><tr><td><a href="/high-performance/jvm/metaspace-oom">元空间溢出排查</a></td><td>动态类加载问题</td></tr><tr><td><a href="/high-performance/jvm/memory-leak">内存泄漏分析</a></td><td>常见泄漏场景与定位</td></tr><tr><td><a href="/high-performance/jvm/cpu-high">CPU 飙高排查</a></td><td>定位 CPU 热点代码</td></tr></tbody></table><h3 id="工具与实战" tabindex="-1">工具与实战 <a class="header-anchor" href="#工具与实战" aria-label="Permalink to “工具与实战”">​</a></h3><table tabindex="0"><thead><tr><th>文档</th><th>简介</th></tr></thead><tbody><tr><td><a href="/high-performance/jvm/arthas">Arthas 诊断工具</a></td><td>热修复、火焰图、方法追踪</td></tr><tr><td><a href="/high-performance/jvm/memory-tools">JVM 调优工具</a></td><td>jmap、jstat、jinfo 使用</td></tr><tr><td><a href="/high-performance/jvm/tuning-summary">JVM 调优总结</a></td><td>调优方法论与案例</td></tr></tbody></table><hr><h2 id="jvm-调优的核心问题" tabindex="-1">JVM 调优的核心问题 <a class="header-anchor" href="#jvm-调优的核心问题" aria-label="Permalink to “JVM 调优的核心问题”">​</a></h2><h3 id="问题一-gc-频繁导致停顿" tabindex="-1">问题一：GC 频繁导致停顿 <a class="header-anchor" href="#问题一-gc-频繁导致停顿" aria-label="Permalink to “问题一：GC 频繁导致停顿”">​</a></h3><p>GC 停顿是 Java 应用最大的性能杀手之一。</p><p>表现：</p><ul><li>用户请求响应时间忽高忽低</li><li>GC 日志显示频繁的 Full GC</li><li>停顿时间长达几秒</li></ul><p>解决方案：</p><ul><li>增大堆内存，减少 GC 频率</li><li>选择更合适的垃圾收集器（G1、ZGC）</li><li>优化对象分配（对象池化、减少大对象）</li></ul><h3 id="问题二-内存泄漏导致-oom" tabindex="-1">问题二：内存泄漏导致 OOM <a class="header-anchor" href="#问题二-内存泄漏导致-oom" aria-label="Permalink to “问题二：内存泄漏导致 OOM”">​</a></h3><p>内存泄漏是生产环境的常见问题。</p><p>常见泄漏场景：</p><table tabindex="0"><thead><tr><th>泄漏场景</th><th>典型案例</th><th>排查方法</th></tr></thead><tbody><tr><td>集合类泄漏</td><td>static Map 持续增长</td><td>MAT dump 分析</td></tr><tr><td>资源未关闭</td><td>数据库连接未释放</td><td>代码审查</td></tr><tr><td>监听器未注销</td><td>事件监听器堆积</td><td>堆快照对比</td></tr><tr><td>ThreadLocal 泄漏</td><td>线程池中 ThreadLocal 未清理</td><td>jstack 线程分析</td></tr></tbody></table><h3 id="问题三-gc-参数配置不当" tabindex="-1">问题三：GC 参数配置不当 <a class="header-anchor" href="#问题三-gc-参数配置不当" aria-label="Permalink to “问题三：GC 参数配置不当”">​</a></h3><p>JVM 参数有几百个，配置不当可能导致性能下降。</p><p>常见误区：</p><ul><li>堆内存设置过大：GC 停顿时间变长</li><li>堆内存设置过小：频繁 GC，吞吐量下降</li><li>年轻代设置过大：老年代空间不足，频繁 Full GC</li><li>年轻代设置过小：对象过早晋升，触发 Full GC</li></ul><hr><h2 id="垃圾收集器的演进" tabindex="-1">垃圾收集器的演进 <a class="header-anchor" href="#垃圾收集器的演进" aria-label="Permalink to “垃圾收集器的演进”">​</a></h2><h3 id="经典收集器" tabindex="-1">经典收集器 <a class="header-anchor" href="#经典收集器" aria-label="Permalink to “经典收集器”">​</a></h3><table tabindex="0"><thead><tr><th>收集器</th><th>算法</th><th>停顿时间</th><th>适用场景</th></tr></thead><tbody><tr><td>Serial</td><td>单线程标记-复制</td><td>长（Stop The World）</td><td>单核、低内存</td></tr><tr><td>Parallel</td><td>多线程标记-复制</td><td>长</td><td>多核、批处理</td></tr><tr><td>CMS</td><td>并发标记-清除</td><td>短</td><td>互联网应用</td></tr><tr><td>G1</td><td>分区+标记-整理</td><td>可控</td><td>替代 CMS</td></tr></tbody></table><h3 id="现代收集器-jdk-11" tabindex="-1">现代收集器（JDK 11+） <a class="header-anchor" href="#现代收集器-jdk-11" aria-label="Permalink to “现代收集器（JDK 11+）”">​</a></h3><table tabindex="0"><thead><tr><th>收集器</th><th>算法</th><th>停顿时间</th><th>特点</th></tr></thead><tbody><tr><td>ZGC</td><td>着色指针+读屏障</td><td>&lt;1ms</td><td>低延迟、大堆</td></tr><tr><td>Shenandoah</td><td>转发指针</td><td>&lt;1ms</td><td>OpenJDK 专用</td></tr><tr><td>Epsilon</td><td>无操作</td><td>无</td><td>短命程序</td></tr></tbody></table><p><strong>JDK 17+ 推荐</strong>：追求低延迟用 ZGC，追求高吞吐用 G1。</p><hr><h2 id="学习路径建议" tabindex="-1">学习路径建议 <a class="header-anchor" href="#学习路径建议" aria-label="Permalink to “学习路径建议”">​</a></h2><h3 id="入门-理解-jvm-内存模型" tabindex="-1">入门：理解 JVM 内存模型 <a class="header-anchor" href="#入门-理解-jvm-内存模型" aria-label="Permalink to “入门：理解 JVM 内存模型”">​</a></h3><p>建议先学习<strong>堆内存参数</strong>和<strong>GC 基础</strong>。</p><p>理解 JVM 内存如何划分，对象如何在堆中分配和回收。这些是调优的基础。</p><h3 id="进阶-掌握-gc-调优" tabindex="-1">进阶：掌握 GC 调优 <a class="header-anchor" href="#进阶-掌握-gc-调优" aria-label="Permalink to “进阶：掌握 GC 调优”">​</a></h3><p>深入学习<strong>GC 日志分析</strong>和<strong>G1 调优</strong>。</p><p>G1 是 JDK 9+ 的默认收集器，也是目前最通用的选择。掌握 G1 的参数配置和问题排查，是 JVM 调优的必备技能。</p><h3 id="高级-解决-oom-问题" tabindex="-1">高级：解决 OOM 问题 <a class="header-anchor" href="#高级-解决-oom-问题" aria-label="Permalink to “高级：解决 OOM 问题”">​</a></h3><p>学习<strong>内存泄漏分析</strong>和<strong>Arthas 诊断工具</strong>。</p><p>OOM 是生产环境最紧急的问题。能够在高压下快速定位问题，是高级工程师的核心能力。</p><hr><h2 id="延伸思考" tabindex="-1">延伸思考 <a class="header-anchor" href="#延伸思考" aria-label="Permalink to “延伸思考”">​</a></h2><p>JVM 调优有个「三七法则」：</p><p><strong>70% 的 JVM 问题，可以通过合理的内存配置解决。</strong></p><p><strong>20% 的问题，需要调整 GC 参数。</strong></p><p><strong>10% 的问题，需要修改代码。</strong></p><p>所以，调优的顺序是：</p><ol><li>先用默认配置，观察 GC 行为</li><li>调整内存大小，让 GC 频率合理</li><li>选择合适的垃圾收集器</li><li>调整 GC 参数，优化停顿时间</li><li>如果还不行，从代码层面优化对象分配</li></ol><p><strong>记住：JVM 调优是最后的手段，不是第一选择。先优化代码，再考虑调优 JVM。</strong></p><p>下一模块，我们将探讨高可用架构——让系统在故障中依然稳定运行。</p>',62)])])}const f=a(h,[["render",i]]);export{s as __pageData,f as default};
